#include <stdio.h>
#include <string.h>

#include "esp_console.h"
#include "esp_log.h"
#include "esp_wiremux.h"
#include "esp_wiremux_console.h"
#include "esp_wiremux_log.h"
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "sdkconfig.h"

static const char *TAG = "esp_wiremux_professional_demo";
static const size_t STRESS_SAMPLE_COUNT = 96;

static esp_err_t bind_demo_console(esp_wiremux_console_mode_t mode)
{
    esp_wiremux_console_config_t console_config;
    esp_wiremux_console_config_init(&console_config);
    console_config.channel_id = 1;
    console_config.mode = mode;
    if (mode == ESP_WIREMUX_CONSOLE_MODE_PASSTHROUGH) {
        console_config.passthrough_backend =
            ESP_WIREMUX_PASSTHROUGH_BACKEND_CONSOLE_LINE_DISCIPLINE;
    }
    return esp_wiremux_bind_console(&console_config);
}

static int help_command(int argc, char **argv)
{
    (void)argc;
    (void)argv;
    return esp_wiremux_write_text(1,
                                  ESP_WIREMUX_DIRECTION_OUTPUT,
                                  "available commands: help hello mux_manifest mux_console_mode mux_hello mux_log mux_utf8 mux_stress mux_diag\n",
                                  20);
}

static int hello_command(int argc, char **argv)
{
    (void)argc;
    (void)argv;
    return esp_wiremux_write_text(1,
                                  ESP_WIREMUX_DIRECTION_OUTPUT,
                                  "hello from esp_wiremux console demo\n",
                                  20);
}

static int mux_manifest_command(int argc, char **argv)
{
    (void)argc;
    (void)argv;
    esp_err_t err = esp_wiremux_emit_manifest(20);
    if (err == ESP_OK) {
        err = esp_wiremux_write_text(1,
                                     ESP_WIREMUX_DIRECTION_OUTPUT,
                                     "manifest emitted on channel 0\n",
                                     20);
    }
    return err;
}

static int mux_console_mode_command(int argc, char **argv)
{
    if (argc != 2 ||
        (strcmp(argv[1], "line") != 0 && strcmp(argv[1], "passthrough") != 0)) {
        return esp_wiremux_write_text(1,
                                      ESP_WIREMUX_DIRECTION_OUTPUT,
                                      "usage: mux_console_mode line|passthrough\n",
                                      20);
    }

    const bool passthrough = strcmp(argv[1], "passthrough") == 0;
    esp_err_t err = bind_demo_console(passthrough ?
                                      ESP_WIREMUX_CONSOLE_MODE_PASSTHROUGH :
                                      ESP_WIREMUX_CONSOLE_MODE_LINE);
    if (err != ESP_OK) {
        return err;
    }

    err = esp_wiremux_emit_manifest(20);
    if (err != ESP_OK) {
        return err;
    }

    return esp_wiremux_write_text(1,
                                  ESP_WIREMUX_DIRECTION_OUTPUT,
                                  passthrough ?
                                      "console mode: passthrough\n" :
                                      "console mode: line\n",
                                  20);
}

static int mux_hello_command(int argc, char **argv)
{
    (void)argc;
    (void)argv;
    esp_err_t err = esp_wiremux_write_text(3,
                                           ESP_WIREMUX_DIRECTION_OUTPUT,
                                           "hello from mux telemetry channel\n",
                                           20);
    if (err == ESP_OK) {
        err = esp_wiremux_write_text(1,
                                     ESP_WIREMUX_DIRECTION_OUTPUT,
                                     "telemetry emitted on channel 3\n",
                                     20);
    }
    return err;
}

static int mux_log_command(int argc, char **argv)
{
    (void)argc;
    (void)argv;
    ESP_LOGI(TAG, "log generated by mux_log console command");
    return esp_wiremux_write_text(1,
                                  ESP_WIREMUX_DIRECTION_OUTPUT,
                                  "log emitted on channel 2\n",
                                  20);
}

static int mux_utf8_command(int argc, char **argv)
{
    (void)argc;
    (void)argv;
    esp_err_t err = esp_wiremux_write_text(4,
                                           ESP_WIREMUX_DIRECTION_OUTPUT,
                                           "UTF-8 demo: 你好 wiremux 🚗🎒😄 payload stays intact\n",
                                           20);
    if (err == ESP_OK) {
        err = esp_wiremux_write_text(1,
                                     ESP_WIREMUX_DIRECTION_OUTPUT,
                                     "UTF-8 emoji payload emitted on channel 4\n",
                                     20);
    }
    return err;
}

static int mux_diag_command(int argc, char **argv)
{
    (void)argc;
    (void)argv;

    esp_wiremux_diagnostics_t diagnostics;
    esp_err_t err = esp_wiremux_get_diagnostics(&diagnostics);
    if (err != ESP_OK) {
        return err;
    }

    for (size_t codec = 0; codec < 3; ++codec) {
        const esp_wiremux_codec_stats_t *stats = &diagnostics.compression[codec];
        char line[192];
        uint64_t ratio_milli = 0;
        if (stats->raw_bytes > 0) {
            ratio_milli = (stats->encoded_bytes * 1000u) / stats->raw_bytes;
        }
        snprintf(line,
                 sizeof(line),
                 "codec=%u raw_bytes=%llu encoded_bytes=%llu ratio_milli=%llu encode_us=%llu decode_ok=%lu fallback_count=%lu heap_peak=%u\n",
                 (unsigned)codec,
                 (unsigned long long)stats->raw_bytes,
                 (unsigned long long)stats->encoded_bytes,
                 (unsigned long long)ratio_milli,
                 (unsigned long long)stats->encode_us,
                 (unsigned long)stats->decode_ok,
                 (unsigned long)stats->fallback_count,
                 (unsigned)stats->heap_peak);
        err = esp_wiremux_write_text(1, ESP_WIREMUX_DIRECTION_OUTPUT, line, 20);
        if (err != ESP_OK) {
            return err;
        }
    }
    return ESP_OK;
}

static int mux_stress_command(int argc, char **argv)
{
    (void)argc;
    (void)argv;

    esp_err_t err = esp_wiremux_write_text(1,
                                           ESP_WIREMUX_DIRECTION_OUTPUT,
                                           "starting matched batch compression stress\n",
                                           20);
    if (err != ESP_OK) {
        return err;
    }

    for (size_t i = 0; i < STRESS_SAMPLE_COUNT; ++i) {
        char line[160];
        snprintf(line,
                 sizeof(line),
                 "mock stress seq=%03u component=wiremux phase=batch codec=probe sensor=temp value=24.%02u status=stable pattern=ABCABCABCABC",
                 (unsigned)i,
                 (unsigned)(i % 100));

        err = esp_wiremux_write_text(2, ESP_WIREMUX_DIRECTION_OUTPUT, line, 20);
        if (err != ESP_OK) {
            return err;
        }

        if ((i % 8) == 7) {
            vTaskDelay(pdMS_TO_TICKS(10));
        }
    }

    for (size_t i = 0; i < STRESS_SAMPLE_COUNT; ++i) {
        char line[160];
        snprintf(line,
                 sizeof(line),
                 "mock stress seq=%03u component=wiremux phase=batch codec=probe sensor=temp value=24.%02u status=stable pattern=ABCABCABCABC",
                 (unsigned)i,
                 (unsigned)(i % 100));

        err = esp_wiremux_write_text(3, ESP_WIREMUX_DIRECTION_OUTPUT, line, 20);
        if (err != ESP_OK) {
            return err;
        }

        if ((i % 8) == 7) {
            vTaskDelay(pdMS_TO_TICKS(10));
        }
    }

    return esp_wiremux_write_text(1,
                                  ESP_WIREMUX_DIRECTION_OUTPUT,
                                  "completed matched batch compression stress\n",
                                  20);
}

static void register_demo_commands(void)
{
    const esp_console_cmd_t help_cmd = {
        .command = "help",
        .help = "List mux console demo commands",
        .hint = NULL,
        .func = help_command,
    };
    ESP_ERROR_CHECK(esp_console_cmd_register(&help_cmd));

    const esp_console_cmd_t hello_cmd = {
        .command = "hello",
        .help = "Print a normal console greeting",
        .hint = NULL,
        .func = hello_command,
    };
    ESP_ERROR_CHECK(esp_console_cmd_register(&hello_cmd));

    const esp_console_cmd_t mux_manifest_cmd = {
        .command = "mux_manifest",
        .help = "Emit mux manifest on the system channel",
        .hint = NULL,
        .func = mux_manifest_command,
    };
    ESP_ERROR_CHECK(esp_console_cmd_register(&mux_manifest_cmd));

    const esp_console_cmd_t mux_console_mode_cmd = {
        .command = "mux_console_mode",
        .help = "Switch console channel between line and passthrough modes",
        .hint = NULL,
        .func = mux_console_mode_command,
    };
    ESP_ERROR_CHECK(esp_console_cmd_register(&mux_console_mode_cmd));

    const esp_console_cmd_t mux_hello_cmd = {
        .command = "mux_hello",
        .help = "Emit a sample message on the mux telemetry channel",
        .hint = NULL,
        .func = mux_hello_command,
    };
    ESP_ERROR_CHECK(esp_console_cmd_register(&mux_hello_cmd));

    const esp_console_cmd_t mux_log_cmd = {
        .command = "mux_log",
        .help = "Emit a sample ESP log through the mux log adapter",
        .hint = NULL,
        .func = mux_log_command,
    };
    ESP_ERROR_CHECK(esp_console_cmd_register(&mux_log_cmd));

    const esp_console_cmd_t mux_utf8_cmd = {
        .command = "mux_utf8",
        .help = "Emit UTF-8 and emoji text on the mux UTF-8 demo channel",
        .hint = NULL,
        .func = mux_utf8_command,
    };
    ESP_ERROR_CHECK(esp_console_cmd_register(&mux_utf8_cmd));

    const esp_console_cmd_t mux_stress_cmd = {
        .command = "mux_stress",
        .help = "Emit matched high-volume channel 2 and 3 records for codec comparison",
        .hint = NULL,
        .func = mux_stress_command,
    };
    ESP_ERROR_CHECK(esp_console_cmd_register(&mux_stress_cmd));

    const esp_console_cmd_t mux_diag_cmd = {
        .command = "mux_diag",
        .help = "Emit mux batch/compression diagnostic counters",
        .hint = NULL,
        .func = mux_diag_command,
    };
    ESP_ERROR_CHECK(esp_console_cmd_register(&mux_diag_cmd));
}

static void init_console_dispatcher(void)
{
    esp_console_config_t console_config = ESP_CONSOLE_CONFIG_DEFAULT();
    console_config.max_cmdline_length = 256;
    ESP_ERROR_CHECK(esp_console_init(&console_config));
}

static void init_mux(void)
{
    esp_wiremux_config_t mux_config;
    esp_wiremux_config_init(&mux_config);
    mux_config.max_payload_len = 512;
    mux_config.queue_depth = 32;
    ESP_ERROR_CHECK(esp_wiremux_init(&mux_config));
    ESP_ERROR_CHECK(esp_wiremux_start());

    const esp_wiremux_channel_config_t system_channel = {
        .channel_id = ESP_WIREMUX_CHANNEL_SYSTEM,
        .name = "system",
        .description = "System manifest and control messages",
        .directions = ESP_WIREMUX_DIRECTION_INPUT | ESP_WIREMUX_DIRECTION_OUTPUT,
        .default_payload_kind = ESP_WIREMUX_PAYLOAD_KIND_CONTROL,
        .flush_policy = ESP_WIREMUX_FLUSH_IMMEDIATE,
        .backpressure_policy = ESP_WIREMUX_BACKPRESSURE_BLOCK_WITH_TIMEOUT,
    };
    ESP_ERROR_CHECK(esp_wiremux_register_channel(&system_channel));

    ESP_ERROR_CHECK(bind_demo_console(ESP_WIREMUX_CONSOLE_MODE_LINE));

    esp_wiremux_log_config_t log_config;
    esp_wiremux_log_config_init(&log_config);
    log_config.channel_id = 2;
    log_config.tee_to_previous = false;
    ESP_ERROR_CHECK(esp_wiremux_bind_esp_log(&log_config));

    const esp_wiremux_channel_config_t telemetry_channel = {
        .channel_id = 3,
        .name = "telemetry",
        .description = "Demo application text output",
        .directions = ESP_WIREMUX_DIRECTION_OUTPUT,
        .default_payload_kind = ESP_WIREMUX_PAYLOAD_KIND_TEXT,
        .flush_policy = ESP_WIREMUX_FLUSH_PERIODIC,
        .backpressure_policy = ESP_WIREMUX_BACKPRESSURE_DROP_OLDEST,
        .output_policy = {
            .send_mode = ESP_WIREMUX_SEND_BATCHED,
            .compression = ESP_WIREMUX_COMPRESSION_LZ4,
            .batch_interval_ms = 100,
            .batch_max_bytes = 384,
        },
    };
    ESP_ERROR_CHECK(esp_wiremux_register_channel(&telemetry_channel));

    const esp_wiremux_channel_config_t utf8_channel = {
        .channel_id = 4,
        .name = "🚗🎒😄🔥",
        .description = "Demo UTF-8 and emoji text output",
        .directions = ESP_WIREMUX_DIRECTION_OUTPUT,
        .default_payload_kind = ESP_WIREMUX_PAYLOAD_KIND_TEXT,
        .flush_policy = ESP_WIREMUX_FLUSH_PERIODIC,
        .backpressure_policy = ESP_WIREMUX_BACKPRESSURE_DROP_OLDEST,
        .output_policy = {
            .send_mode = ESP_WIREMUX_SEND_BATCHED,
            .compression = ESP_WIREMUX_COMPRESSION_LZ4,
            .batch_interval_ms = 100,
            .batch_max_bytes = 384,
        },
    };
    ESP_ERROR_CHECK(esp_wiremux_register_channel(&utf8_channel));

    ESP_ERROR_CHECK(esp_wiremux_emit_manifest(20));
}

static void telemetry_task(void *arg)
{
    (void)arg;

    vTaskDelay(pdMS_TO_TICKS(1200));
    (void)esp_wiremux_emit_manifest(20);

    uint32_t counter = 0;
    while (true) {
        char message[96];
        snprintf(message, sizeof(message), "demo telemetry sample count=%lu\n", (unsigned long)counter++);
        (void)esp_wiremux_write_text(3,
                                     ESP_WIREMUX_DIRECTION_OUTPUT,
                                     message,
                                     20);
        char utf8_message[128];
        snprintf(utf8_message,
                 sizeof(utf8_message),
                 "UTF-8 telemetry 样本=%lu emoji=🚗🎒😄\n",
                 (unsigned long)counter);
        (void)esp_wiremux_write_text(4,
                                     ESP_WIREMUX_DIRECTION_OUTPUT,
                                     utf8_message,
                                     20);
        ESP_LOGI(TAG, "demo periodic log count=%lu", (unsigned long)counter);
        vTaskDelay(pdMS_TO_TICKS(2000));
    }
}

void app_main(void)
{
    init_console_dispatcher();
    init_mux();
    register_demo_commands();

    ESP_ERROR_CHECK(xTaskCreate(telemetry_task,
                                "mux_telemetry_demo",
                                3072,
                                NULL,
                                4,
                                NULL) == pdPASS ? ESP_OK : ESP_ERR_NO_MEM);

    ESP_LOGI(TAG, "mux demo started");
    ESP_ERROR_CHECK(esp_wiremux_write_text(3,
                                           ESP_WIREMUX_DIRECTION_OUTPUT,
                                           "demo telemetry initial sample\n",
                                           20));
    ESP_ERROR_CHECK(esp_wiremux_write_text(4,
                                           ESP_WIREMUX_DIRECTION_OUTPUT,
                                           "UTF-8 initial sample 你好 🚗🎒😄\n",
                                           20));

    while (true) {
        vTaskDelay(portMAX_DELAY);
    }
}
